#### **阶段 4: 创建审计日志查询服务** (1-2 小时)

```typescript
// 文件: src/dashboard/services/audit.service.ts

import Database from 'better-sqlite3';
import { getDatabaseService } from './database.service';

export interface AuditLog {
  id: number;
  tableName: string;
  recordId: number;
  action: 'INSERT' | 'UPDATE' | 'DELETE';
  oldData: string | null;
  newData: string | null;
  changedBy: string;
  changedAt: Date;
}

export interface AuditLogFilter {
  tableName?: string;
  recordId?: number;
  action?: 'INSERT' | 'UPDATE' | 'DELETE';
  changedBy?: string;
  startDate?: Date;
  endDate?: Date;
}

export class AuditService {
  private db: Database.Database;

  constructor() {
    this.db = getDatabaseService().connect();
  }

  /**
   * 查询审计日志
   */
  async queryLogs(
    filter: AuditLogFilter,
    pagination: { page: number; limit: number } = { page: 1, limit: 50 }
  ): Promise<{ data: AuditLog[]; total: number }> {
    const { page, limit } = pagination;
    const offset = (page - 1) * limit;

    // 构建 WHERE 条件
    const conditions: string[] = ['1=1'];
    const params: any[] = [];

    if (filter.tableName) {
      conditions.push('table_name = ?');
      params.push(filter.tableName);
    }

    if (filter.recordId) {
      conditions.push('record_id = ?');
      params.push(filter.recordId);
    }

    if (filter.action) {
      conditions.push('action = ?');
      params.push(filter.action);
    }

    if (filter.changedBy) {
      conditions.push('changed_by = ?');
      params.push(filter.changedBy);
    }

    if (filter.startDate) {
      conditions.push('changed_at >= ?');
      params.push(filter.startDate.toISOString());
    }

    if (filter.endDate) {
      conditions.push('changed_at <= ?');
      params.push(filter.endDate.toISOString());
    }

    const whereClause = conditions.join(' AND ');

    // 查询总数
    const countResult = this.db
      .prepare(`SELECT COUNT(*) as total FROM audit_logs WHERE ${whereClause}`)
      .get(...params) as { total: number };

    // 查询数据
    const data = this.db
      .prepare(
        `
        SELECT 
          id,
          table_name as tableName,
          record_id as recordId,
          action,
          old_data as oldData,
          new_data as newData,
          changed_by as changedBy,
          changed_at as changedAt
        FROM audit_logs
        WHERE ${whereClause}
        ORDER BY changed_at DESC
        LIMIT ? OFFSET ?
        `
      )
      .all(...params, limit, offset) as AuditLog[];

    return {
      data,
      total: countResult.total
    };
  }

  /**
   * 获取记录的变更历史
   */
  async getRecordHistory(tableName: string, recordId: number): Promise<AuditLog[]> {
    const logs = this.db
      .prepare(
        `
        SELECT 
          id,
          table_name as tableName,
          record_id as recordId,
          action,
          old_data as oldData,
          new_data as newData,
          changed_by as changedBy,
          changed_at as changedAt
        FROM audit_logs
        WHERE table_name = ? AND record_id = ?
        ORDER BY changed_at ASC
        `
      )
      .all(tableName, recordId) as AuditLog[];

    return logs;
  }

  /**
   * 清理旧审计日志
   */
  async cleanupOldLogs(daysToKeep: number = 90): Promise<number> {
    const cutoffDate = new Date();
    cutoffDate.setDate(cutoffDate.getDate() - daysToKeep);

    const result = this.db
      .prepare('DELETE FROM audit_logs WHERE changed_at < ?')
      .run(cutoffDate.toISOString());

    console.log(`🧹 清理了 ${result.changes} 条旧审计日志`);
    return result.changes;
  }

  /**
   * 导出审计日志（CSV/JSON）
   */
  async exportLogs(
    filter: AuditLogFilter,
    format: 'json' | 'csv' = 'json'
  ): Promise<string> {
    const { data } = await this.queryLogs(filter, { page: 1, limit: 10000 });

    if (format === 'json') {
      return JSON.stringify(data, null, 2);
    } else {
      // CSV 格式
      const headers = ['ID', 'Table', 'Record ID', 'Action', 'Changed By', 'Changed At', 'Old Data', 'New Data'];
      const rows = data.map(log => [
        log.id,
        log.tableName,
        log.recordId,
        log.action,
        log.changedBy,
        log.changedAt,
        log.oldData,
        log.newData
      ]);

      return [headers, ...rows]
        .map(row => row.map(cell => `"${cell || ''}"`).join(','))
        .join('\n');
    }
  }
}

export default AuditService;
```

