## 🎯 改进任务：PostgreSQL 物化视图自动刷新机制

### 📊 当前问题分析

查看 `database/ai_team_system.sql`，项目使用了 3 个物化视图：

| 物化视图 | 用途 | 当前问题 |
|:---------|:-----|:---------|
| `iteration_summary` | 迭代概览统计 | 需要手动刷新 |
| `agent_performance_stats` | Agent 性能统计 | 数据非实时 |
| `real_time_metrics` | 实时性能指标 | **名字叫"实时"但需手动刷新** ❌ |

**影响**：
- Dashboard 展示的统计数据可能过期
- 用户看到的 Agent 性能指标不是最新的
- "实时"指标名不副实

---

### 💡 改进方案

#### 方案一：PostgreSQL 原生定时任务（推荐）⭐⭐⭐⭐⭐

使用 `pg_cron` 扩展实现自动刷新：

```sql
-- =====================================================
-- 物化视图自动刷新机制
-- =====================================================

-- 1. 确保 pg_cron 扩展已安装（已有）
-- CREATE EXTENSION IF NOT EXISTS "pg_cron";

-- 2. 创建物化视图刷新函数
CREATE OR REPLACE FUNCTION refresh_dashboard_materialized_views()
RETURNS JSONB AS $$
DECLARE
    start_time TIMESTAMP := NOW();
    duration_ms INTEGER;
    result JSONB := '{"refreshes": []}'::JSONB;
    iteration_result TEXT;
    agent_result TEXT;
    metrics_result TEXT;
BEGIN
    -- 刷新 iteration_summary（每分钟）
    REFRESH MATERIALIZED VIEW CONCURRENTLY iteration_summary;
    GET DIAGNOSTICS iteration_result = ROW_COUNT;

    -- 刷新 agent_performance_stats（每5分钟）
    REFRESH MATERIALIZED VIEW CONCURRENTLY agent_performance_stats;
    GET DIAGNOSTICS agent_result = ROW_COUNT;

    -- 刷新 real_time_metrics（每30秒）
    REFRESH MATERIALIZED VIEW CONCURRENTLY real_time_metrics;
    GET DIAGNOSTICS metrics_result = ROW_COUNT;

    -- 计算耗时
    duration_ms := EXTRACT(EPOCH FROM (NOW() - start_time)) * 1000;

    -- 构建结果
    result := jsonb_build_object(
        'timestamp', start_time,
        'duration_ms', duration_ms,
        'refreshes', jsonb_build_array(
            jsonb_build_object('view', 'iteration_summary', 'status', 'success'),
            jsonb_build_object('view', 'agent_performance_stats', 'status', 'success'),
            jsonb_build_object('view', 'real_time_metrics', 'status', 'success')
        ),
        'success', true
    );

    -- 记录刷新日志（可选）
    INSERT INTO performance_metrics (metric_name, metric_value, tags)
    VALUES (
        'materialized_view_refresh_duration',
        duration_ms,
        jsonb_build_object('source', 'pg_cron')
    );

    RETURN result;
EXCEPTION
    WHEN OTHERS THEN
        -- 错误处理
        result := jsonb_build_object(
            'timestamp', start_time,
            'error', SQLERRM,
            'success', false
        );

        -- 记录错误
        INSERT INTO performance_metrics (metric_name, metric_value, tags)
        VALUES (
            'materialized_view_refresh_error',
            1,
            jsonb_build_object('error', SQLERRM)
        );

        RETURN result;
END;
$$ LANGUAGE plpgsql;

COMMENT ON FUNCTION refresh_dashboard_materialized_views() IS '刷新所有 Dashboard 物化视图';

-- 3. 创建定时任务
-- 刷新 real_time_metrics（每30秒）
SELECT cron.schedule(
    'refresh-real-time-metrics',
    '*/30 * * * *',  -- 每30秒
    $$SELECT REFRESH MATERIALIZED VIEW CONCURRENTLY real_time_metrics$$
);

-- 刷新 iteration_summary（每1分钟）
SELECT cron.schedule(
    'refresh-iteration-summary',
    '* * * * *',  -- 每1分钟
    $$SELECT REFRESH MATERIALIZED VIEW CONCURRENTLY iteration_summary$$
);

-- 刷新 agent_performance_stats（每5分钟）
SELECT cron.schedule(
    'refresh-agent-performance',
    '*/5 * * * *',  -- 每5分钟
    $$SELECT REFRESH MATERIALIZED VIEW CONCURRENTLY agent_performance_stats$$
);

-- 4. 监控定时任务状态
CREATE OR REPLACE FUNCTION get_cron_jobs_status()
RETURNS TABLE (
    jobid BIGINT,
    schedule VARCHAR,
    command TEXT,
    status VARCHAR,
    last_run TIMESTAMP,
    next_run TIMESTAMP
) AS $$
BEGIN
    RETURN QUERY
    SELECT 
        jobid,
        schedule,
        command,
        'active'::VARCHAR,
        NOW() AS last_run,
        NOW() + INTERVAL '1 minute' AS next_run
    FROM cron.job
    WHERE command LIKE '%REFRESH MATERIALIZED VIEW%'
    ORDER BY jobid;
END;
$$ LANGUAGE plpgsql;

-- 5. 查看定时任务
-- SELECT * FROM get_cron_jobs_status();
-- SELECT * FROM cron.job WHERE command LIKE '%REFRESH%';
```

**优点**：
- ✅ 完全在数据库层实现，无需应用层代码
- ✅ 精确的时间控制（30秒、1分钟、5分钟）
- ✅ 使用 `CONCURRENTLY` 不阻塞查询
- ✅ 自动错误处理和日志记录

