```typescript
// src/dashboard/services/materialized-view.service.ts
import { getDatabase } from '../database'

export class MaterializedViewService {
  private refreshIntervals: NodeJS.Timeout[] = []

  // 启动自动刷新
  startAutoRefresh() {
    // real_time_metrics: 每30秒
    this.refreshIntervals.push(
      setInterval(async () => {
        await this.refreshView('real_time_metrics')
      }, 30000)
    )

    // iteration_summary: 每1分钟
    this.refreshIntervals.push(
      setInterval(async () => {
        await this.refreshView('iteration_summary')
      }, 60000)
    )

    // agent_performance_stats: 每5分钟
    this.refreshIntervals.push(
      setInterval(async () => {
        await this.refreshView('agent_performance_stats')
      }, 300000)
    )
  }

  private async refreshView(viewName: string) {
    const db = getDatabase()

    try {
      const start = Date.now()
      await db.raw(`REFRESH MATERIALIZED VIEW CONCURRENTLY ${viewName}`)
      const duration = Date.now() - start

      console.log(`✅ Refreshed ${viewName} in ${duration}ms`)

      // 记录性能指标
      await db('performance_metrics').insert({
        metric_name: 'materialized_view_refresh_duration',
        metric_value: duration,
        tags: { view: viewName, source: 'app' }
      })
    } catch (error) {
      console.error(`❌ Failed to refresh ${viewName}:`, error)

      // 记录错误
      await db('performance_metrics').insert({
        metric_name: 'materialized_view_refresh_error',
        metric_value: 1,
        tags: { view: viewName, error: error.message }
      })
    }
  }

  stopAutoRefresh() {
    this.refreshIntervals.forEach(clearInterval)
    this.refreshIntervals = []
  }
}

export const materializedViewService = new MaterializedViewService()
