// src/dashboard/services/performance-tracker.ts

export class PerformanceTracker {
  private metrics: Map<string, OperationMetric> = new Map();

  recordOperation(operation: {
    type: 'query' | 'queryOne' | 'execute' | 'transaction';
    sql: string;
    duration: number;
    success: boolean;
  }): void {
    const template = this.extractSqlTemplate(operation.sql);
    const key = `${operation.type}:${template}`;

    // 记录到内存
    this.updateMetric(key, operation);

    // 记录慢操作到数据库
    if (operation.duration > 100) {
      this.saveSlowOperation(operation, template);
    }
  }

  private saveSlowOperation(operation: any, template: string): void {
    this.db.execute(`
      INSERT INTO database_performance_metrics
      (operation_type, sql_template, execution_time_ms, tags)
      VALUES (?, ?, ?, ?)
    `, [
      operation.type,
      template,
      operation.duration,
      JSON.stringify({ success: operation.success })
    ]);
  }

  // 获取性能统计
  getStats(): PerformanceStats {
    return {
      totalOperations: this.metrics.size,
      slowOperations: Array.from(this.metrics.values())
        .filter(m => m.avgDuration > 100).length,
      topSlowOperations: this.getTopSlowOperations(10)
    };
  }
}
```

**Step 3: 重构 DatabaseService (40分钟)**
```typescript
export class DatabaseService {
  private performanceTracker: PerformanceTracker;

  constructor(config: DatabaseConfig) {
    this.config = config;
    this.performanceTracker = new PerformanceTracker(this);
  }

  // 统一的执行包装器
  private executeWithTracking<T>(
    operationType: string,
    sql: string,
    fn: () => T
  ): T {
    const startTime = Date.now();
    try {
      const result = fn();
      const duration = Date.now() - startTime;

      // 记录性能
      this.performanceTracker.recordOperation({
        type: operationType,
        sql,
        duration,
        success: true
      });

      // 慢操作告警
      if (duration > 100) {
        console.warn(`⚠️ Slow ${operationType} (${duration}ms): ${sql.substring(0, 100)}...`);
      }

      return result;
    } catch (error) {
      const duration = Date.now() - startTime;
      this.performanceTracker.recordOperation({
        type: operationType,
        sql,
        duration,
        success: false
      });
      throw error;
    }
  }

  // 使用包装器重构
  query<T = any>(sql: string, params: any[] = []): T[] {
    return this.executeWithTracking('query', sql, () => {
      const stmt = this.connect().prepare(sql);
      return stmt.all(...params) as T[];
    });
  }

  queryOne<T = any>(sql: string, params: any[] = []): T | null {
    return this.executeWithTracking('queryOne', sql, () => {
      const stmt = this.connect().prepare(sql);
      return stmt.get(...params) as T | undefined || null;
    });
  }

  execute(sql: string, params: any[] = []): Database.RunResult {
    return this.executeWithTracking('execute', sql, () => {
      const stmt = this.connect().prepare(sql);
      return stmt.run(...params);
    });
  }
}
```

