      sql_template,
      COUNT(*) as count,
      AVG(execution_time_ms) as avg_time
    FROM database_performance_metrics
    WHERE timestamp > datetime('now', '-24 hours')
    GROUP BY sql_template
    ORDER BY avg_time DESC
    LIMIT 10
  `);

  return {
    totalQueries: result.length,
    avgQueryTime: 0, // 计算平均时间
    slowQueryCount: result.filter(r => r.avg_time > 100).length,
    topSlowQueries: result
  };
}
