#### 2. 实现 `DatabaseService` 增强（1.5小时）

```typescript
export class DatabaseService {
  private queryStats = new Map<string, {
    count: number;
    totalTime: number;
    maxTime: number;
    minTime: number;
    slowCount: number;
  }>();
  private slowQueryThreshold = 100; // ms

  /**
   * 记录查询性能（内存缓存）
   */
  private recordQueryPerformance(sql: string, duration: number): void {
    const template = this.extractQueryTemplate(sql);
    const stats = this.queryStats.get(template) || {
      count: 0,
      totalTime: 0,
      maxTime: 0,
      minTime: Infinity,
      slowCount: 0
    };

    stats.count++;
    stats.totalTime += duration;
    stats.maxTime = Math.max(stats.maxTime, duration);
    stats.minTime = Math.min(stats.minTime, duration);

    if (duration > this.slowQueryThreshold) {
      stats.slowCount++;
    }

    this.queryStats.set(template, stats);

    // 每 10 次查询或遇到慢查询时，持久化到数据库
    if (stats.count % 10 === 0 || duration > this.slowQueryThreshold) {
      this.persistQueryStats(template, stats);
    }
  }

  /**
   * 持久化查询统计到数据库
   */
  private persistQueryStats(template: string, stats: any): void {
    const sql = `
      INSERT INTO query_performance_log 
      (query_template, execution_count, total_time_ms, avg_time_ms, 
       max_time_ms, min_time_ms, slow_count, last_executed_at)
      VALUES (?, ?, ?, ?, ?, ?, ?, CURRENT_TIMESTAMP)
      ON CONFLICT(query_template) 
      DO UPDATE SET
        execution_count = execution_count + ?,
        total_time_ms = total_time_ms + ?,
        avg_time_ms = (total_time_ms + ?) / (execution_count + 1),
        max_time_ms = MAX(max_time_ms, ?),
        min_time_ms = CASE 
          WHEN min_time_ms = 0 THEN ? 
          ELSE MIN(min_time_ms, ?) 
        END,
        slow_count = slow_count + ?,
        last_executed_at = CURRENT_TIMESTAMP
    `;

    this.execute(sql, [
      template,
      stats.count, stats.totalTime, stats.totalTime / stats.count,
      stats.maxTime, stats.minTime === Infinity ? 0 : stats.minTime,
      stats.slowCount,
      stats.count, stats.totalTime, stats.totalTime,
      stats.maxTime, stats.minTime === Infinity ? 0 : stats.minTime,
      stats.minTime === Infinity ? 0 : stats.minTime,
      stats.slowCount
    ]);
  }

  /**
   * 提取查询模板（去除参数）
   */
  private extractQueryTemplate(sql: string): string {
    return sql
      .replace(/\d+/g, '?')           // 数字替换为 ?
      .replace(/'[^']*'/g, '?')       // 字符串替换为 ?
      .replace(/\s+/g, ' ')           // 多个空格压缩为一个
      .trim()
      .substring(0, 200);             // 限制长度
  }

  /**
   * 增强的查询方法
   */
  query<T = any>(sql: string, params: any[] = []): T[] {
    const db = this.connect();
    const stmt = db.prepare(sql);
    const startTime = Date.now();

    try {
      const results = stmt.all(...params) as T[];
      const duration = Date.now() - startTime;

      // ✅ 记录查询性能
      this.recordQueryPerformance(sql, duration);

      // ✅ 慢查询告警
      if (duration > this.slowQueryThreshold) {
        console.warn(
          `⚠️ Slow query (${duration}ms): ` +
          `${this.extractQueryTemplate(sql)}`
        );
      }

      return results;
    } catch (error) {
      console.error(`❌ Query failed: ${sql}`, error);
      throw error;
    }
  }

  /**
   * 获取查询性能统计 TOP N
   */
  getTopSlowQueries(limit: number = 10): any[] {
    const sql = `
      SELECT 
        query_template,
        execution_count,
        avg_time_ms,
        max_time_ms,
        slow_count,
        last_executed_at
      FROM query_performance_log
      WHERE slow_count > 0
      ORDER BY avg_time_ms DESC
      LIMIT ?
    `;
    return this.query(sql, [limit]);
  }

  /**
   * 实现慢查询日志方法
   */
  logSlowQueries(thresholdMs: number = 100): void {
    this.slowQueryThreshold = thresholdMs;
    console.log(`📊 Slow query threshold updated: ${thresholdMs}ms`);

    // 输出当前统计
    const slowQueries = this.getTopSlowQueries(10);
    console.table(slowQueries);
  }

  /**
   * 清理旧的性能日志（保留最近 7 天）
   */
  cleanupOldPerformanceLogs(): void {
    const sql = `
      DELETE FROM query_performance_log 
      WHERE last_executed_at < datetime('now', '-7 days')
    `;
    const result = this.execute(sql);
    console.log(`🧹 Cleaned up ${result.changes} old performance logs`);
  }
}
```

